$challenge=\dataphyre\caspow::create_challenge('unit_test_verify', ['hardware_concurrency'=>1,'device_memory'=>1,'save_data'=>true,'reduced_motion'=>true]);
$counter=0;
$digest='';
$target=(int)$challenge['difficulty_bits'];
while(true){
	$digest=hash('sha256', $challenge['challenge_id'].':'.$challenge['nonce'].':'.$counter);
	$bits=0;
	for($i=0; $i<strlen($digest); $i++){
		$nibble=hexdec($digest[$i]);
		if($nibble===0){
			$bits+=4;
			continue;
		}
		if(($nibble & 8)===0){ $bits++; } else { break; }
		if(($nibble & 4)===0){ $bits++; } else { break; }
		if(($nibble & 2)===0){ $bits++; } else { break; }
		if(($nibble & 1)===0){ $bits++; }
		break;
	}
	if($bits>=$target){
		break;
	}
	$counter++;
}
return base64_encode(json_encode([
	'version'=>$challenge['version'],
	'challenge_id'=>$challenge['challenge_id'],
	'scope'=>$challenge['scope'],
	'algorithm'=>$challenge['algorithm'],
	'nonce'=>$challenge['nonce'],
	'signature'=>$challenge['signature'],
	'counter'=>$counter,
	'digest'=>$digest,
	'duration_ms'=>1,
	'iterations'=>$counter+1,
	'worker'=>false,
]));

